// 25 TypeScript Tutorials with full 3-phase content
module.exports = function (T, S) {
  return [
    T({ title: 'TypeScript Type Annotations', slug: 'ts-type-annotations', description: 'Learn basic type annotations for variables, functions, and parameters.', language: 'typescript', difficulty: 'beginner', duration: 30, tags: ['typescript', 'types', 'annotations', 'fundamentals'], objectives: ['Annotate variables with types', 'Type function parameters and returns', 'Use basic types'], featured: true, steps: [
      S(1, { title: 'Basic Type Annotations', content: 'TypeScript adds static types to JavaScript using annotations after colons.', lang: 'typescript', code: 'let name: string = "Alice";\nlet age: number = 30;\nlet active: boolean = true;\nlet items: string[] = ["a", "b", "c"];\n\nfunction greet(name: string): string {\n  return `Hello, ${name}!`;\n}\nconsole.log(greet("Alice"));', concept: 'Type annotations tell TypeScript the expected type of a value. The compiler catches mismatches at build time, preventing runtime errors.', keyPoints: ['string, number, boolean are primitives', 'Arrays: type[] or Array<type>', 'Function params and return types', 'Type errors caught at compile time'], realWorld: 'API endpoint handlers type their request body to catch missing fields before deployment.', mistakes: ['Using String instead of string (capital S is the wrapper object)', 'Over-annotating when inference works', 'Ignoring compiler errors with any'], pInstructions: ['Annotate variables of each basic type', 'Write a typed function', 'Try passing wrong types to see errors'], starter: '// Annotate these variables\nlet username = "Bob";\nlet score = 95;\nlet passed = true;\nlet grades = [90, 85, 92];\n\n// Add types to this function\nfunction calculateAvg(numbers) {\n  return numbers.reduce((a, b) => a + b, 0) / numbers.length;\n}\n\nconsole.log(calculateAvg(grades));', solution: 'let username: string = "Bob";\nlet score: number = 95;\nlet passed: boolean = true;\nlet grades: number[] = [90, 85, 92];\n\nfunction calculateAvg(numbers: number[]): number {\n  return numbers.reduce((a, b) => a + b, 0) / numbers.length;\n}\n\nconsole.log(calculateAvg(grades));', hints: ['Add : type after variable names', 'Function return type goes after params: (): type'], challenge: 'Create a typed function that formats user data, rejecting invalid types at compile time.', reqs: ['Accept name: string, age: number, email: string', 'Return a formatted string', 'TypeScript should error on wrong types'], tests: [['formatUser("A",30,"a@b.c")', '"A (30) - a@b.c"', 5]] }),
    ] }),

    T({ title: 'TypeScript Interfaces', slug: 'ts-interfaces', description: 'Define object shapes with interfaces for type-safe code.', language: 'typescript', difficulty: 'beginner', duration: 35, tags: ['typescript', 'interfaces', 'types', 'objects'], objectives: ['Define interfaces for objects', 'Use optional and readonly properties', 'Extend interfaces'], steps: [
      S(1, { title: 'Defining Interfaces', content: 'Interfaces describe the shape of objects, enforcing consistent structure.', lang: 'typescript', code: 'interface User {\n  id: number;\n  name: string;\n  email: string;\n  age?: number;  // optional\n  readonly createdAt: Date;\n}\n\nfunction displayUser(user: User): string {\n  return `${user.name} (${user.email})`;\n}\n\nconst user: User = { id: 1, name: "Alice", email: "alice@test.com", createdAt: new Date() };\nconsole.log(displayUser(user));', concept: 'Interfaces define contracts for object shapes. Optional properties use ?. readonly prevents modification after creation.', keyPoints: ['interface defines object shape', '? marks optional properties', 'readonly prevents reassignment', 'extends for interface inheritance'], realWorld: 'API response types ensure your code handles all fields correctly. Component props in React use interfaces.', mistakes: ['Forgetting required properties', 'Trying to modify readonly properties', 'Not using optional for nullable fields'], pInstructions: ['Define an interface for a product', 'Create objects conforming to the interface', 'Use the interface in a function'], starter: 'interface Product {\n  // Define properties: id, name, price, description (optional), inStock\n}\n\nfunction formatProduct(product: Product): string {\n  // Return formatted string\n  return "";\n}\n\nconst laptop: Product = {\n  // Create a product\n};\nconsole.log(formatProduct(laptop));', solution: 'interface Product {\n  id: number;\n  name: string;\n  price: number;\n  description?: string;\n  inStock: boolean;\n}\n\nfunction formatProduct(product: Product): string {\n  return `${product.name} - $${product.price} ${product.inStock ? "(In Stock)" : "(Out of Stock)"}`;\n}\n\nconst laptop: Product = { id: 1, name: "Laptop", price: 999.99, inStock: true };\nconsole.log(formatProduct(laptop));', hints: ['Use ? after property name for optional', 'Boolean properties are common for flags'], challenge: 'Create an interface hierarchy: Shape -> Circle, Rectangle with area() method.', reqs: ['Base Shape interface with name and color', 'Circle adds radius', 'Rectangle adds width and height', 'Each has area calculation'], tests: [['circle area', 'π*r²', 5], ['rectangle area', 'w*h', 5]] }),
    ] }),

    T({ title: 'TypeScript Union and Intersection Types', slug: 'ts-union-intersection', description: 'Combine types with union (|) and intersection (&) operators.', language: 'typescript', difficulty: 'intermediate', duration: 40, tags: ['typescript', 'union-types', 'intersection', 'advanced-types'], objectives: ['Use union types for flexibility', 'Use intersection types for combining', 'Apply type narrowing'], steps: [
      S(1, { title: 'Union Types and Narrowing', content: 'Union types allow a value to be one of several types; narrowing refines the type.', lang: 'typescript', code: 'type StringOrNumber = string | number;\n\nfunction format(value: StringOrNumber): string {\n  if (typeof value === "string") {\n    return value.toUpperCase(); // narrowed to string\n  }\n  return value.toFixed(2); // narrowed to number\n}\n\nconsole.log(format("hello")); // HELLO\nconsole.log(format(3.14159)); // 3.14', concept: 'Union types (A | B) mean "A or B". TypeScript narrows the type inside conditional blocks using typeof, instanceof, or custom type guards.', keyPoints: ['| for union (either type)', '& for intersection (both types)', 'typeof for primitive narrowing', 'Custom type guards for complex types'], realWorld: 'API responses may return Success | Error. Function params accept string | string[] for flexibility.', mistakes: ['Not narrowing before type-specific operations', 'Confusing union with intersection', 'Forgetting to handle all union members'], pInstructions: ['Create a union type', 'Write a function with type narrowing', 'Create an intersection type'], starter: 'type Result = { success: true; data: string } | { success: false; error: string };\n\nfunction handleResult(result: Result): string {\n  // Narrow and handle both cases\n  return "";\n}\n\nconsole.log(handleResult({ success: true, data: "Done!" }));\nconsole.log(handleResult({ success: false, error: "Failed" }));', solution: 'type Result = { success: true; data: string } | { success: false; error: string };\n\nfunction handleResult(result: Result): string {\n  if (result.success) {\n    return `Success: ${result.data}`;\n  }\n  return `Error: ${result.error}`;\n}\n\nconsole.log(handleResult({ success: true, data: "Done!" }));\nconsole.log(handleResult({ success: false, error: "Failed" }));', hints: ['Check the discriminant property (success)', 'TypeScript narrows automatically'], challenge: 'Build a type-safe event system where each event type has its own payload shape.', reqs: ['Union of event types', 'Type-safe emit function', 'Exhaustive switch handling'], tests: [['emit("click", {x:0,y:0})', 'type-safe', 5]] }),
    ] }),

    T({ title: 'TypeScript Generics', slug: 'ts-generics', description: 'Write reusable, type-safe code with generic types and functions.', language: 'typescript', difficulty: 'intermediate', duration: 45, tags: ['typescript', 'generics', 'type-safety', 'reusable'], objectives: ['Write generic functions', 'Create generic interfaces and classes', 'Apply constraints to generics'], featured: true, steps: [
      S(1, { title: 'Generic Functions', content: 'Generics let you write functions that work with any type while preserving type safety.', lang: 'typescript', code: 'function identity<T>(value: T): T {\n  return value;\n}\n\nfunction firstElement<T>(arr: T[]): T | undefined {\n  return arr[0];\n}\n\nconsole.log(identity<string>("hello")); // "hello"\nconsole.log(identity(42)); // 42 (inferred)\nconsole.log(firstElement([1, 2, 3])); // 1', concept: 'Generic type parameters (<T>) act as placeholders. TypeScript infers the concrete type from usage, or you can specify it explicitly.', keyPoints: ['<T> declares a type parameter', 'Type inference fills in T automatically', 'Constraints: <T extends SomeType>', 'Multiple type params: <T, U>'], realWorld: 'Array<T>, Promise<T>, Map<K,V> are all generic. React useState<T> preserves the state type.', mistakes: ['Using any instead of generics', 'Over-constraining generics', 'Forgetting that T could be any type'], pInstructions: ['Write a generic identity function', 'Write a generic array wrapper', 'Add constraints to a generic'], starter: 'function wrapInArray<T>(value: T): T[] {\n  return [value];\n}\n\nfunction merge<T, U>(a: T, b: U): T & U {\n  return { ...a as any, ...b as any };\n}\n\nconsole.log(wrapInArray("hello"));\nconsole.log(wrapInArray(42));\nconsole.log(merge({ name: "Alice" }, { age: 30 }));', solution: 'function wrapInArray<T>(value: T): T[] {\n  return [value];\n}\n\nfunction merge<T, U>(a: T, b: U): T & U {\n  return { ...a as any, ...b as any };\n}\n\nconsole.log(wrapInArray("hello"));\nconsole.log(wrapInArray(42));\nconsole.log(merge({ name: "Alice" }, { age: 30 }));', hints: ['<T> goes before the parameter list', 'Return type uses the same T'], challenge: 'Create a generic Stack<T> class with push, pop, peek, and isEmpty methods.', reqs: ['Fully generic — works with any type', 'Type-safe push/pop/peek', 'Handle empty stack'], tests: [['Stack<number> push/pop', 'typed correctly', 5]] }),
      S(2, { title: 'Generic Constraints', content: 'Constraints limit what types a generic can accept using extends.', lang: 'typescript', code: 'interface HasLength {\n  length: number;\n}\n\nfunction logLength<T extends HasLength>(item: T): T {\n  console.log(`Length: ${item.length}`);\n  return item;\n}\n\nlogLength("hello");     // Length: 5\nlogLength([1, 2, 3]);   // Length: 3\n// logLength(42);       // Error! number has no length', concept: 'Constraints ensure the generic type has certain properties. Use extends to require that T has specific structure.', keyPoints: ['extends narrows what T can be', 'keyof for key constraints', 'Conditional types for advanced logic', 'Default type parameters'], realWorld: 'A database ORM uses generics with constraints: find<T extends Model>(id: number): T.', mistakes: ['Too tight constraints (defeats generics purpose)', 'Forgetting constraint means T could be anything', 'Not using keyof for property access'], pInstructions: ['Add extends constraint to a generic', 'Use keyof for property access', 'Create a generic with default type'], starter: 'function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {\n  return obj[key];\n}\n\nconst user = { name: "Alice", age: 30, email: "alice@test.com" };\nconsole.log(getProperty(user, "name"));\nconsole.log(getProperty(user, "age"));\n// getProperty(user, "phone"); // Should error', solution: 'function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {\n  return obj[key];\n}\n\nconst user = { name: "Alice", age: 30, email: "alice@test.com" };\nconsole.log(getProperty(user, "name"));\nconsole.log(getProperty(user, "age"));', hints: ['keyof T gets all property names', 'T[K] is the type of property K'], challenge: 'Build a type-safe object mapper that transforms object values while preserving keys.', reqs: ['Generic mapper function', 'Preserve key types', 'Transform value types'], tests: [['mapValues({a:1}, n=>n*2)', '{a:2}', 5]] }),
    ] }),

    T({ title: 'TypeScript Enums and Literal Types', slug: 'ts-enums-literals', description: 'Use enums for named constants and literal types for exact values.', language: 'typescript', difficulty: 'beginner', duration: 30, tags: ['typescript', 'enums', 'literal-types', 'constants'], objectives: ['Define and use enums', 'Use string and numeric literal types', 'Choose between enums and unions'], steps: [
      S(1, { title: 'Enums and Literal Types', content: 'Enums define named constants. Literal types restrict values to exact strings or numbers.', lang: 'typescript', code: 'enum Direction {\n  Up = "UP",\n  Down = "DOWN",\n  Left = "LEFT",\n  Right = "RIGHT"\n}\n\nfunction move(dir: Direction): string {\n  return `Moving ${dir}`;\n}\nconsole.log(move(Direction.Up));\n\n// Literal type union (often preferred over enum)\ntype Color = "red" | "green" | "blue";\nlet bg: Color = "red";\nconsole.log(bg);', concept: 'Enums create a set of named constants. String literal unions (type X = "a" | "b") are a lightweight alternative often preferred in modern TypeScript.', keyPoints: ['String enums are more readable', 'Literal unions are tree-shakeable', 'const enum for inlining', 'Exhaustiveness checking with never'], realWorld: 'HTTP methods (GET|POST|PUT|DELETE), user roles (admin|user|guest), status codes.', mistakes: ['Using numeric enums without explicit values', 'Not using as const for literal inference', 'Mixing enum patterns'], pInstructions: ['Create a string enum for HTTP methods', 'Create a literal union type for status', 'Use both in a function'], starter: 'enum HttpMethod {\n  // Define GET, POST, PUT, DELETE\n}\n\ntype Status = "pending" | "active" | "inactive";\n\nfunction makeRequest(method: HttpMethod, url: string): string {\n  return `${method} ${url}`;\n}\n\nfunction getStatusColor(status: Status): string {\n  // Return color for each status\n  return "";\n}\n\nconsole.log(makeRequest(HttpMethod.GET, "/api/users"));\nconsole.log(getStatusColor("active"));', solution: 'enum HttpMethod {\n  GET = "GET",\n  POST = "POST",\n  PUT = "PUT",\n  DELETE = "DELETE"\n}\n\ntype Status = "pending" | "active" | "inactive";\n\nfunction makeRequest(method: HttpMethod, url: string): string {\n  return `${method} ${url}`;\n}\n\nfunction getStatusColor(status: Status): string {\n  switch (status) {\n    case "pending": return "yellow";\n    case "active": return "green";\n    case "inactive": return "gray";\n  }\n}\n\nconsole.log(makeRequest(HttpMethod.GET, "/api/users"));\nconsole.log(getStatusColor("active"));', hints: ['String enum: Key = "VALUE"', 'Switch handles all literal union members'], challenge: 'Create a state machine type where each state only allows valid transitions.', reqs: ['Define states as literal union', 'Transition function only accepts valid next states', 'TypeScript errors on invalid transitions'], tests: [['transition("idle","running")', 'valid', 5]] }),
    ] }),

    T({ title: 'TypeScript Type Guards', slug: 'ts-type-guards', description: 'Narrow types safely with typeof, instanceof, and custom type guards.', language: 'typescript', difficulty: 'intermediate', duration: 40, tags: ['typescript', 'type-guards', 'narrowing', 'safety'], objectives: ['Use built-in type guards', 'Write custom type guard functions', 'Handle discriminated unions'], steps: [
      S(1, { title: 'Type Narrowing', content: 'Type guards help TypeScript narrow a wider type to a more specific one.', lang: 'typescript', code: 'interface Cat { kind: "cat"; meow(): string; }\ninterface Dog { kind: "dog"; bark(): string; }\ntype Pet = Cat | Dog;\n\nfunction speak(pet: Pet): string {\n  switch (pet.kind) {\n    case "cat": return pet.meow();\n    case "dog": return pet.bark();\n  }\n}\n\nfunction isCat(pet: Pet): pet is Cat {\n  return pet.kind === "cat";\n}\n\nconst myPet: Pet = { kind: "cat", meow: () => "Meow!" };\nif (isCat(myPet)) {\n  console.log(myPet.meow());\n}', concept: 'Discriminated unions use a common property (like kind) to distinguish between types. Custom type guards (: x is Type) let TypeScript narrow in custom functions.', keyPoints: ['typeof for primitives', 'instanceof for classes', 'Discriminated unions with literal property', 'Custom guards: param is Type'], realWorld: 'API responses often return different shapes. Type guards let you safely access specific fields.', mistakes: ['Type guard returning wrong boolean', 'Not handling all discriminants', 'Using as instead of proper narrowing'], pInstructions: ['Create a discriminated union', 'Write a switch for exhaustive handling', 'Write a custom type guard'], starter: 'type Shape =\n  | { kind: "circle"; radius: number }\n  | { kind: "rectangle"; width: number; height: number }\n  | { kind: "triangle"; base: number; height: number };\n\nfunction area(shape: Shape): number {\n  // Handle all shapes\n  return 0;\n}\n\nconsole.log(area({ kind: "circle", radius: 5 }));\nconsole.log(area({ kind: "rectangle", width: 4, height: 6 }));\nconsole.log(area({ kind: "triangle", base: 3, height: 8 }));', solution: 'type Shape =\n  | { kind: "circle"; radius: number }\n  | { kind: "rectangle"; width: number; height: number }\n  | { kind: "triangle"; base: number; height: number };\n\nfunction area(shape: Shape): number {\n  switch (shape.kind) {\n    case "circle": return Math.PI * shape.radius ** 2;\n    case "rectangle": return shape.width * shape.height;\n    case "triangle": return 0.5 * shape.base * shape.height;\n  }\n}\n\nconsole.log(area({ kind: "circle", radius: 5 }));\nconsole.log(area({ kind: "rectangle", width: 4, height: 6 }));\nconsole.log(area({ kind: "triangle", base: 3, height: 8 }));', hints: ['switch on the kind property', 'TypeScript narrows inside each case'], challenge: 'Add exhaustiveness checking using the never type to ensure all cases are handled.', reqs: ['Add a default case that assigns to never', 'If a new shape is added, TypeScript errors', 'Create assertNever helper'], tests: [['all shapes handled', 'no error', 5]] }),
    ] }),

    T({ title: 'TypeScript Utility Types', slug: 'ts-utility-types', description: 'Use Partial, Required, Pick, Omit, Record, and other built-in utility types.', language: 'typescript', difficulty: 'intermediate', duration: 40, tags: ['typescript', 'utility-types', 'partial', 'pick'], objectives: ['Use Partial and Required', 'Use Pick and Omit', 'Use Record and Readonly'], steps: [
      S(1, { title: 'Built-in Utility Types', content: 'TypeScript provides utility types for common type transformations.', lang: 'typescript', code: 'interface User {\n  id: number;\n  name: string;\n  email: string;\n  age: number;\n}\n\n// Partial - all optional\ntype UserUpdate = Partial<User>;\n\n// Pick - select properties\ntype UserPreview = Pick<User, "id" | "name">;\n\n// Omit - exclude properties\ntype UserCreate = Omit<User, "id">;\n\nconst update: UserUpdate = { name: "Bob" }; // OK\nconst preview: UserPreview = { id: 1, name: "Alice" };\nconst create: UserCreate = { name: "Charlie", email: "c@test.com", age: 25 };\nconsole.log(update, preview, create);', concept: 'Utility types transform existing types: Partial makes all props optional, Pick selects specific props, Omit removes props, Record creates a map type.', keyPoints: ['Partial<T> — all optional', 'Required<T> — all required', 'Pick<T, Keys> — select properties', 'Omit<T, Keys> — exclude properties', 'Record<K, V> — key-value map'], realWorld: 'Update endpoints use Partial<User> (only send changed fields). List views use Pick<User, "id"|"name"> for previews.', mistakes: ['Overusing Partial (hides required fields)', 'Not combining utility types', 'Using Omit when Pick is clearer'], pInstructions: ['Apply Partial to make all fields optional', 'Use Pick to select specific fields', 'Combine utility types'], starter: 'interface Todo {\n  id: number;\n  title: string;\n  description: string;\n  completed: boolean;\n  createdAt: Date;\n}\n\n// Create type without id and createdAt\ntype CreateTodo = \n\n// Update type with all optional fields\ntype UpdateTodo = \n\n// Summary type with just id, title, completed\ntype TodoSummary = \n\nconst newTodo: CreateTodo = { title: "Learn TS", description: "Study utility types", completed: false };\nconsole.log(newTodo);', solution: 'interface Todo {\n  id: number;\n  title: string;\n  description: string;\n  completed: boolean;\n  createdAt: Date;\n}\n\ntype CreateTodo = Omit<Todo, "id" | "createdAt">;\ntype UpdateTodo = Partial<Todo>;\ntype TodoSummary = Pick<Todo, "id" | "title" | "completed">;\n\nconst newTodo: CreateTodo = { title: "Learn TS", description: "Study utility types", completed: false };\nconsole.log(newTodo);', hints: ['Omit removes specified keys', 'Partial makes everything optional'], challenge: 'Build a custom DeepPartial<T> type that makes all nested properties optional too.', reqs: ['Handle nested objects', 'Handle arrays', 'Preserve non-object types'], tests: [['DeepPartial<{a:{b:string}}>', '{a?:{b?:string}}', 5]] }),
    ] }),

    T({ title: 'TypeScript Classes', slug: 'ts-classes', description: 'Build type-safe classes with access modifiers, abstract classes, and implements.', language: 'typescript', difficulty: 'intermediate', duration: 45, tags: ['typescript', 'classes', 'oop', 'access-modifiers'], objectives: ['Use public/private/protected', 'Create abstract classes', 'Implement interfaces'], steps: [
      S(1, { title: 'Typed Classes', content: 'TypeScript adds access modifiers and type checking to JavaScript classes.', lang: 'typescript', code: 'class BankAccount {\n  private balance: number;\n  readonly owner: string;\n\n  constructor(owner: string, initial: number) {\n    this.owner = owner;\n    this.balance = initial;\n  }\n\n  deposit(amount: number): void {\n    if (amount > 0) this.balance += amount;\n  }\n\n  getBalance(): number {\n    return this.balance;\n  }\n}\n\nconst acc = new BankAccount("Alice", 1000);\nacc.deposit(500);\nconsole.log(acc.getBalance());', concept: 'Access modifiers control property visibility: public (default), private (class only), protected (class + subclasses). readonly prevents reassignment.', keyPoints: ['private — only within class', 'protected — class + subclasses', 'readonly — set once in constructor', 'Parameter properties shorthand'], realWorld: 'Domain models: User class with private password hash, public profile fields, protected internal methods.', mistakes: ['Forgetting private still exists at runtime (as suggestion)', 'Not using parameter properties shorthand', 'Making everything public'], pInstructions: ['Create a class with access modifiers', 'Add methods that use private fields', 'Use parameter properties shorthand'], starter: 'class User {\n  // Use parameter properties: public name, private email, readonly id\n  constructor(\n    // your params\n  ) {}\n\n  getEmail(): string {\n    return this.email;\n  }\n\n  updateEmail(newEmail: string): void {\n    // validate and update\n  }\n}\n\nconst user = new User(1, "Alice", "alice@test.com");\nconsole.log(user.name);\nconsole.log(user.getEmail());', solution: 'class User {\n  constructor(\n    public readonly id: number,\n    public name: string,\n    private email: string\n  ) {}\n\n  getEmail(): string {\n    return this.email;\n  }\n\n  updateEmail(newEmail: string): void {\n    if (newEmail.includes("@")) {\n      this.email = newEmail;\n    }\n  }\n}\n\nconst user = new User(1, "Alice", "alice@test.com");\nconsole.log(user.name);\nconsole.log(user.getEmail());', hints: ['Parameter properties: public/private in constructor params', 'readonly can only be set in constructor'], challenge: 'Create an abstract Shape class with abstract area() and concrete toString() methods.', reqs: ['Abstract class cannot be instantiated', 'Subclasses must implement area()', 'toString uses area()'], tests: [['new Circle(5).area()', 'π*25', 5]] }),
    ] }),

    T({ title: 'TypeScript Type Aliases and Mapped Types', slug: 'ts-type-aliases', description: 'Create reusable type aliases and build complex types with mapped types.', language: 'typescript', difficulty: 'intermediate', duration: 40, tags: ['typescript', 'type-aliases', 'mapped-types', 'advanced'], objectives: ['Create type aliases', 'Use template literal types', 'Build mapped types'], steps: [
      S(1, { title: 'Type Aliases and Mapped Types', content: 'Type aliases name complex types. Mapped types transform properties of existing types.', lang: 'typescript', code: 'type ID = string | number;\ntype Callback<T> = (data: T) => void;\n\n// Mapped type: make all properties nullable\ntype Nullable<T> = {\n  [K in keyof T]: T[K] | null;\n};\n\ninterface User { name: string; age: number; }\ntype NullableUser = Nullable<User>;\n\nconst user: NullableUser = { name: "Alice", age: null };\nconsole.log(user);', concept: 'Type aliases create names for complex types. Mapped types iterate over keys using [K in keyof T] to transform each property.', keyPoints: ['type X = ... for aliases', '[K in keyof T] iterates properties', 'Conditional types: T extends U ? X : Y', 'Template literal types for string manipulation'], realWorld: 'Form state types: Nullable<User> for initial empty form, Partial<User> for update payloads.', mistakes: ['Overcomplicating mapped types', 'Not using utility types when they suffice', 'Recursive types without termination'], pInstructions: ['Create type aliases for common patterns', 'Build a custom mapped type', 'Use conditional types'], starter: 'type StringKeys<T> = {\n  [K in keyof T]: T[K] extends string ? K : never;\n}[keyof T];\n\ninterface User {\n  id: number;\n  name: string;\n  email: string;\n  age: number;\n}\n\n// Should be "name" | "email"\ntype UserStringKeys = StringKeys<User>;\n\n// Make all string properties uppercase\ntype Stringify<T> = {\n  [K in keyof T]: string;\n};\n\nconst stringUser: Stringify<User> = { id: "1", name: "Alice", email: "test", age: "30" };\nconsole.log(stringUser);', solution: 'type StringKeys<T> = {\n  [K in keyof T]: T[K] extends string ? K : never;\n}[keyof T];\n\ninterface User {\n  id: number;\n  name: string;\n  email: string;\n  age: number;\n}\n\ntype UserStringKeys = StringKeys<User>;\n\ntype Stringify<T> = {\n  [K in keyof T]: string;\n};\n\nconst stringUser: Stringify<User> = { id: "1", name: "Alice", email: "test", age: "30" };\nconsole.log(stringUser);', hints: ['[K in keyof T] maps over each key', 'Conditional type: T extends U ? X : Y'], challenge: 'Create a DeepReadonly<T> type that makes all nested properties readonly.', reqs: ['Handle nested objects', 'Handle arrays', 'Preserve primitive types'], tests: [['DeepReadonly<{a:{b:1}}>', 'fully readonly', 5]] }),
    ] }),

    T({ title: 'TypeScript Async Patterns', slug: 'ts-async-patterns', description: 'Type-safe async/await, Promise types, and error handling patterns.', language: 'typescript', difficulty: 'intermediate', duration: 40, tags: ['typescript', 'async', 'promises', 'error-handling'], objectives: ['Type Promise return values', 'Handle async errors type-safely', 'Use generic async patterns'], steps: [
      S(1, { title: 'Typed Async Functions', content: 'TypeScript provides full type safety for async operations.', lang: 'typescript', code: 'interface ApiResponse<T> {\n  data: T;\n  status: number;\n}\n\nasync function fetchUser(id: number): Promise<ApiResponse<{name: string}>> {\n  // Simulated\n  return { data: { name: "Alice" }, status: 200 };\n}\n\nasync function main() {\n  const response = await fetchUser(1);\n  console.log(response.data.name); // Type-safe!\n}\nmain();', concept: 'Async functions return Promise<T> where T is the resolved type. Generic async patterns create reusable API wrappers.', keyPoints: ['Return type is Promise<T>', 'await unwraps Promise to T', 'Generic responses: ApiResponse<T>', 'Type-safe error handling'], realWorld: 'HTTP clients type their responses: fetchUser returns Promise<User>, fetchPosts returns Promise<Post[]>.', mistakes: ['Not typing Promise return values', 'Unhandled promise rejections', 'Using any for API responses'], pInstructions: ['Write a typed async function', 'Create a generic API response type', 'Add error handling'], starter: 'type Result<T, E = Error> =\n  | { ok: true; value: T }\n  | { ok: false; error: E };\n\nasync function safeFetch<T>(url: string): Promise<Result<T>> {\n  // Simulate fetch with error handling\n  try {\n    // Simulated success\n    const data = {} as T;\n    return { ok: true, value: data };\n  } catch (e) {\n    return { ok: false, error: e as Error };\n  }\n}\n\nasync function main() {\n  const result = await safeFetch<{name: string}>("/api/user");\n  if (result.ok) {\n    console.log(result.value.name);\n  }\n}\nmain();', solution: 'type Result<T, E = Error> =\n  | { ok: true; value: T }\n  | { ok: false; error: E };\n\nasync function safeFetch<T>(url: string): Promise<Result<T>> {\n  try {\n    const data = { name: "Alice" } as unknown as T;\n    return { ok: true, value: data };\n  } catch (e) {\n    return { ok: false, error: e as Error };\n  }\n}\n\nasync function main() {\n  const result = await safeFetch<{name: string}>("/api/user");\n  if (result.ok) {\n    console.log(result.value.name);\n  } else {\n    console.error(result.error.message);\n  }\n}\nmain();', hints: ['Result type wraps success/failure', 'Discriminate with result.ok'], challenge: 'Build a typed retry wrapper with exponential backoff.', reqs: ['Generic return type', 'Configurable max retries', 'Type-safe error handling'], tests: [['retry succeeds on 2nd try', 'returns value', 5]] }),
    ] }),

    T({ title: 'TypeScript Decorators', slug: 'ts-decorators', description: 'Use decorators for cross-cutting concerns like logging, validation, and caching.', language: 'typescript', difficulty: 'advanced', duration: 45, tags: ['typescript', 'decorators', 'metadata', 'aop'], objectives: ['Write class decorators', 'Write method decorators', 'Use decorator factories'], steps: [
      S(1, { title: 'Method Decorators', content: 'Decorators modify classes and methods at design time using the @ syntax.', lang: 'typescript', code: 'function log(target: any, key: string, desc: PropertyDescriptor) {\n  const original = desc.value;\n  desc.value = function(...args: any[]) {\n    console.log(`Calling ${key} with`, args);\n    const result = original.apply(this, args);\n    console.log(`${key} returned`, result);\n    return result;\n  };\n}\n\nclass Calculator {\n  @log\n  add(a: number, b: number): number {\n    return a + b;\n  }\n}\n\nnew Calculator().add(2, 3);', concept: 'Method decorators receive the target, method name, and property descriptor. They can wrap the original method to add behavior.', keyPoints: ['Class decorators modify constructor', 'Method decorators wrap methods', 'Property decorators add metadata', 'Decorator factories return decorators'], realWorld: 'NestJS uses @Controller, @Get, @Post. Angular uses @Component, @Injectable for dependency injection.', mistakes: ['Wrong decorator signature', 'Not preserving this context', 'Decorator order matters (bottom-up)'], pInstructions: ['Write a logging method decorator', 'Write a timing decorator', 'Write a decorator factory with options'], starter: 'function validate(target: any, key: string, desc: PropertyDescriptor) {\n  const original = desc.value;\n  desc.value = function(...args: any[]) {\n    // Validate all args are numbers\n    // Throw if invalid\n    return original.apply(this, args);\n  };\n}\n\nclass MathService {\n  @validate\n  divide(a: number, b: number): number {\n    return a / b;\n  }\n}\n\nconst math = new MathService();\nconsole.log(math.divide(10, 2));', solution: 'function validate(target: any, key: string, desc: PropertyDescriptor) {\n  const original = desc.value;\n  desc.value = function(...args: any[]) {\n    for (const arg of args) {\n      if (typeof arg !== "number" || isNaN(arg)) {\n        throw new Error(`Invalid argument: ${arg}`);\n      }\n    }\n    if (args[1] === 0 && key === "divide") {\n      throw new Error("Division by zero");\n    }\n    return original.apply(this, args);\n  };\n}\n\nclass MathService {\n  @validate\n  divide(a: number, b: number): number {\n    return a / b;\n  }\n}\n\nconst math = new MathService();\nconsole.log(math.divide(10, 2));', hints: ['desc.value is the original method', 'Use original.apply(this, args) to call it'], challenge: 'Create a @cache decorator that memoizes method results based on arguments.', reqs: ['Cache based on serialized args', 'Support TTL (time to live)', 'Add cache.clear() capability'], tests: [['cached method called twice', 'computed once', 5]] }),
    ] }),

    T({ title: 'TypeScript Module Patterns', slug: 'ts-module-patterns', description: 'Organize TypeScript code with modules, namespaces, and barrel exports.', language: 'typescript', difficulty: 'intermediate', duration: 35, tags: ['typescript', 'modules', 'namespaces', 'organization'], objectives: ['Use ES module imports/exports', 'Create barrel exports', 'Understand declaration files'], steps: [
      S(1, { title: 'Module Organization', content: 'TypeScript uses ES modules with additional features like declaration files.', lang: 'typescript', code: '// Types are exportable just like values\nexport interface User {\n  id: number;\n  name: string;\n}\n\nexport type UserRole = "admin" | "user" | "guest";\n\nexport function createUser(name: string, role: UserRole): User {\n  return { id: Math.random(), name };\n}\n\n// Re-export patterns\n// export { User, createUser } from "./user";\n\nconst user = createUser("Alice", "admin");\nconsole.log(user);', concept: 'TypeScript modules export types alongside values. Declaration files (.d.ts) provide types for JavaScript libraries. Barrel exports (index.ts) aggregate re-exports.', keyPoints: ['Export types and interfaces', 'import type for type-only imports', 'Declaration files (.d.ts)', 'Barrel exports: export * from'], realWorld: 'Large projects organize types in a types/ directory, with barrel exports for clean import paths.', mistakes: ['Circular type dependencies', 'Not using import type (affects bundling)', 'Exporting too much from barrel files'], pInstructions: ['Export types alongside values', 'Create a module with related types and functions', 'Organize with barrel exports'], starter: '// Simulated module pattern\ninterface Config {\n  apiUrl: string;\n  timeout: number;\n  debug: boolean;\n}\n\nfunction createConfig(overrides: Partial<Config> = {}): Config {\n  const defaults: Config = {\n    apiUrl: "https://api.example.com",\n    timeout: 5000,\n    debug: false\n  };\n  return { ...defaults, ...overrides };\n}\n\nconst config = createConfig({ debug: true });\nconsole.log(config);', solution: 'interface Config {\n  apiUrl: string;\n  timeout: number;\n  debug: boolean;\n}\n\nfunction createConfig(overrides: Partial<Config> = {}): Config {\n  const defaults: Config = {\n    apiUrl: "https://api.example.com",\n    timeout: 5000,\n    debug: false\n  };\n  return { ...defaults, ...overrides };\n}\n\nconst config = createConfig({ debug: true });\nconsole.log(config);', hints: ['Partial<Config> makes all properties optional', 'Spread merges defaults with overrides'], challenge: 'Design a plugin system with typed plugin interfaces and dynamic loading.', reqs: ['Plugin interface with init() and destroy()', 'Plugin registry with type safety', 'Load plugins by name'], tests: [['register and load plugin', 'initialized', 5]] }),
    ] }),

    T({ title: 'TypeScript Conditional Types', slug: 'ts-conditional-types', description: 'Build advanced types with conditional logic and infer keyword.', language: 'typescript', difficulty: 'advanced', duration: 50, tags: ['typescript', 'conditional-types', 'infer', 'advanced'], objectives: ['Write conditional types', 'Use infer keyword', 'Build complex type utilities'], steps: [
      S(1, { title: 'Conditional and Infer Types', content: 'Conditional types enable type-level if/else logic using extends and infer.', lang: 'typescript', code: 'type IsString<T> = T extends string ? true : false;\n\ntype A = IsString<"hello">; // true\ntype B = IsString<42>;      // false\n\n// infer extracts types from patterns\ntype ReturnType2<T> = T extends (...args: any[]) => infer R ? R : never;\n\nfunction greet(name: string): string { return `Hi, ${name}`; }\ntype GreetReturn = ReturnType2<typeof greet>; // string\n\nconst x: GreetReturn = "hello";\nconsole.log(x);', concept: 'T extends U ? X : Y chooses types based on conditions. infer declares a type variable within the condition, extracting parts of a type.', keyPoints: ['extends checks type compatibility', 'True/false branches like ternary', 'infer extracts from type patterns', 'Distributive over unions'], realWorld: 'Framework types: extracting component props type, inferring async function return types, extracting Promise values.', mistakes: ['Not understanding distributive behavior', 'Over-nesting conditional types', 'Using any instead of proper conditionals'], pInstructions: ['Write basic conditional types', 'Use infer to extract types', 'Build a utility type with conditionals'], starter: '// Extract the element type from an array\ntype ElementOf<T> = T extends (infer E)[] ? E : T;\n\ntype A = ElementOf<string[]>;  // string\ntype B = ElementOf<number>;    // number\n\n// Unwrap a Promise type\ntype Unwrap<T> = T extends Promise<infer U> ? U : T;\n\ntype C = Unwrap<Promise<string>>; // string\ntype D = Unwrap<number>;          // number\n\nconst a: A = "hello";\nconst c: C = "world";\nconsole.log(a, c);', solution: 'type ElementOf<T> = T extends (infer E)[] ? E : T;\n\ntype A = ElementOf<string[]>;\ntype B = ElementOf<number>;\n\ntype Unwrap<T> = T extends Promise<infer U> ? U : T;\n\ntype C = Unwrap<Promise<string>>;\ntype D = Unwrap<number>;\n\nconst a: A = "hello";\nconst c: C = "world";\nconsole.log(a, c);', hints: ['infer E captures the array element type', 'infer U captures the Promise value type'], challenge: 'Build a PathKeys<T> type that extracts all valid dot-notation paths from a nested object type.', reqs: ['Handle nested objects', 'Support array indices', 'Return union of all valid paths'], tests: [['PathKeys<{a:{b:string}}>', '"a" | "a.b"', 5]] }),
    ] }),

    T({ title: 'TypeScript Error Handling Patterns', slug: 'ts-error-handling', description: 'Type-safe error handling with discriminated unions and Result types.', language: 'typescript', difficulty: 'intermediate', duration: 35, tags: ['typescript', 'errors', 'result-type', 'safety'], objectives: ['Create Result type for errors', 'Use discriminated unions for errors', 'Handle errors type-safely'], steps: [
      S(1, { title: 'Result Pattern', content: 'The Result pattern provides type-safe error handling without try/catch.', lang: 'typescript', code: 'type Result<T, E = string> =\n  | { success: true; data: T }\n  | { success: false; error: E };\n\nfunction divide(a: number, b: number): Result<number> {\n  if (b === 0) return { success: false, error: "Division by zero" };\n  return { success: true, data: a / b };\n}\n\nconst result = divide(10, 3);\nif (result.success) {\n  console.log(`Result: ${result.data.toFixed(2)}`);\n} else {\n  console.error(result.error);\n}', concept: 'The Result type forces callers to handle both success and failure cases. TypeScript narrows the type based on the success flag.', keyPoints: ['Discriminated union for success/failure', 'Compiler forces error handling', 'No uncaught exceptions', 'Composable with map/flatMap'], realWorld: 'Rust\'s Result type. API client libraries wrap responses in Result to force error handling.', mistakes: ['Not checking success before accessing data', 'Using exceptions for expected failures', 'Mixing Result and throw patterns'], pInstructions: ['Define a Result type', 'Write functions that return Results', 'Chain Results together'], starter: 'type Result<T, E = string> =\n  | { ok: true; value: T }\n  | { ok: false; error: E };\n\nfunction parseJSON<T>(str: string): Result<T> {\n  // Parse safely\n  try {\n    return { ok: true, value: JSON.parse(str) };\n  } catch (e) {\n    return { ok: false, error: (e as Error).message };\n  }\n}\n\nconst good = parseJSON<{name: string}>(\'{\"name\":\"Alice\"}\');\nconst bad = parseJSON<{name: string}>("invalid");\n\nif (good.ok) console.log(good.value.name);\nif (!bad.ok) console.log(bad.error);', solution: 'type Result<T, E = string> =\n  | { ok: true; value: T }\n  | { ok: false; error: E };\n\nfunction parseJSON<T>(str: string): Result<T> {\n  try {\n    return { ok: true, value: JSON.parse(str) };\n  } catch (e) {\n    return { ok: false, error: (e as Error).message };\n  }\n}\n\nconst good = parseJSON<{name: string}>(\'{\"name\":\"Alice\"}\');\nconst bad = parseJSON<{name: string}>("invalid");\n\nif (good.ok) console.log(good.value.name);\nif (!bad.ok) console.log(bad.error);', hints: ['Return {ok: true, value} or {ok: false, error}', 'Check ok before accessing value'], challenge: 'Build a Result monad with map(), flatMap(), and unwrapOr() methods.', reqs: ['map transforms the value if ok', 'flatMap chains Results', 'unwrapOr provides default'], tests: [['Result.ok(1).map(x=>x*2)', '{ok:true,value:2}', 5]] }),
    ] }),

    T({ title: 'TypeScript Strict Mode and Configuration', slug: 'ts-strict-mode', description: 'Configure tsconfig.json for maximum type safety and understand strict mode flags.', language: 'typescript', difficulty: 'beginner', duration: 30, tags: ['typescript', 'tsconfig', 'strict', 'configuration'], objectives: ['Configure tsconfig.json', 'Understand strict mode flags', 'Fix common strict mode errors'], steps: [
      S(1, { title: 'Strict Mode Flags', content: 'TypeScript strict mode enables all strict type checking options for maximum safety.', lang: 'typescript', code: '// With strict: true\n// strictNullChecks: prevents null/undefined assignment\nlet name: string = "Alice";\n// name = null;  // Error!\nlet maybeName: string | null = null; // OK\n\n// noImplicitAny: requires explicit types\n// function greet(name) {} // Error! Parameter implicitly has any\nfunction greet(name: string): string { return `Hi, ${name}`; }\n\nconsole.log(greet("Alice"));', concept: 'strict: true enables strictNullChecks, noImplicitAny, strictFunctionTypes, and more. Each catches different categories of bugs at compile time.', keyPoints: ['strict: true enables all strict checks', 'strictNullChecks catches null errors', 'noImplicitAny requires explicit types', 'strictFunctionTypes for safe callbacks'], realWorld: 'Production TypeScript projects always use strict mode. It catches bugs that would otherwise cause runtime crashes.', mistakes: ['Using any to silence errors', 'Disabling strict checks instead of fixing types', 'Not handling null cases with strict checks'], pInstructions: ['Enable strict mode in tsconfig', 'Fix code to work with strict null checks', 'Remove implicit any types'], starter: '// Fix these for strict mode\n\nfunction findUser(users: {name: string}[], name: string) {\n  const user = users.find(u => u.name === name);\n  // With strictNullChecks, user could be undefined\n  // Fix: handle the undefined case\n  return user.name; // Error in strict mode!\n}\n\nconst users = [{name: "Alice"}, {name: "Bob"}];\ntry {\n  console.log(findUser(users, "Alice"));\n} catch(e) {\n  console.log("handled");\n}', solution: 'function findUser(users: {name: string}[], name: string): string {\n  const user = users.find(u => u.name === name);\n  if (!user) {\n    throw new Error(`User ${name} not found`);\n  }\n  return user.name;\n}\n\nconst users = [{name: "Alice"}, {name: "Bob"}];\ntry {\n  console.log(findUser(users, "Alice"));\n} catch(e) {\n  console.log("handled");\n}', hints: ['Check for undefined before accessing properties', 'Add explicit return type'], challenge: 'Convert a JavaScript file to strict TypeScript, fixing all type errors.', reqs: ['Add type annotations to all functions', 'Handle all null/undefined cases', 'Remove all implicit any'], tests: [['compiles with strict: true', 'no errors', 5]] }),
    ] }),

    T({ title: 'TypeScript Template Literal Types', slug: 'ts-template-literals', description: 'Build powerful string types with template literal type syntax.', language: 'typescript', difficulty: 'advanced', duration: 40, tags: ['typescript', 'template-literals', 'string-types', 'advanced'], objectives: ['Create template literal types', 'Build type-safe string patterns', 'Combine with mapped types'], steps: [
      S(1, { title: 'Template Literal Types', content: 'Template literal types create new string types from other string types.', lang: 'typescript', code: 'type Color = "red" | "blue" | "green";\ntype Size = "sm" | "md" | "lg";\n\n// Generates: "red-sm" | "red-md" | "red-lg" | "blue-sm" | ...\ntype ColorSize = `${Color}-${Size}`;\n\ntype EventName = "click" | "focus" | "blur";\ntype Handler = `on${Capitalize<EventName>}`;\n// "onClick" | "onFocus" | "onBlur"\n\nconst handler: Handler = "onClick";\nconsole.log(handler);', concept: 'Template literal types use backtick syntax at the type level. They distribute over unions, creating all combinations. Built-in string utilities: Uppercase, Lowercase, Capitalize, Uncapitalize.', keyPoints: ['Backtick syntax at type level', 'Distributes over unions', 'Capitalize, Uppercase utilities', 'Combine with keyof for prop access'], realWorld: 'CSS class generators: type ClassName = `${Size}-${Color}`. Event handlers: type Handlers = `on${Capitalize<EventName>}`.', mistakes: ['Combinatorial explosion with large unions', 'Not using string manipulation utilities', 'Overcomplicating when simpler types work'], pInstructions: ['Create template literal types', 'Use string manipulation utilities', 'Build a type-safe CSS class system'], starter: 'type Direction = "top" | "right" | "bottom" | "left";\ntype Unit = "px" | "rem" | "em";\n\n// Create CSS property types like "margin-top", "padding-left"\ntype SpacingProp = `${"margin" | "padding"}-${Direction}`;\n\n// Create CSS value type like "10px", "2rem"\ntype CSSValue = `${number}${Unit}`;\n\nconst prop: SpacingProp = "margin-top";\nconst value: CSSValue = "10px";\nconsole.log(prop, value);', solution: 'type Direction = "top" | "right" | "bottom" | "left";\ntype Unit = "px" | "rem" | "em";\n\ntype SpacingProp = `${"margin" | "padding"}-${Direction}`;\ntype CSSValue = `${number}${Unit}`;\n\nconst prop: SpacingProp = "margin-top";\nconst value: CSSValue = "10px";\nconsole.log(prop, value);', hints: ['Template literals distribute over unions', '${number} matches any number'], challenge: 'Build a type-safe route path system that extracts parameter types from "/users/:id/posts/:postId".', reqs: ['Extract param names from path string', 'Type params object from path', 'Support multiple params'], tests: [['Params<"/users/:id">', '{id: string}', 5]] }),
    ] }),

    T({ title: 'TypeScript Design Patterns', slug: 'ts-design-patterns', description: 'Implement classic design patterns with full TypeScript type safety.', language: 'typescript', difficulty: 'advanced', duration: 50, tags: ['typescript', 'patterns', 'architecture', 'design'], objectives: ['Type-safe Singleton', 'Generic Observer pattern', 'Builder pattern with types'], steps: [
      S(1, { title: 'Typed Design Patterns', content: 'TypeScript enhances design patterns with type safety and generics.', lang: 'typescript', code: 'class EventEmitter<Events extends Record<string, any>> {\n  private listeners: { [K in keyof Events]?: ((data: Events[K]) => void)[] } = {};\n\n  on<K extends keyof Events>(event: K, fn: (data: Events[K]) => void) {\n    (this.listeners[event] ||= []).push(fn);\n  }\n\n  emit<K extends keyof Events>(event: K, data: Events[K]) {\n    (this.listeners[event] || []).forEach(fn => fn(data));\n  }\n}\n\ninterface AppEvents {\n  login: { userId: string };\n  logout: undefined;\n  error: { message: string; code: number };\n}\n\nconst emitter = new EventEmitter<AppEvents>();\nemitter.on("login", (data) => console.log(`User ${data.userId} logged in`));\nemitter.emit("login", { userId: "123" });', concept: 'TypeScript generics make design patterns type-safe. The Observer pattern with generic events ensures emit and on use matching types.', keyPoints: ['Generics for type-safe patterns', 'Record<string, any> for event maps', 'keyof constrains event names', 'Callback type matches event data'], realWorld: 'Type-safe event systems in React state managers, WebSocket message handlers, and pub/sub systems.', mistakes: ['Not constraining generic enough', 'Losing type safety with any', 'Not using discriminated unions for events'], pInstructions: ['Create a typed event emitter', 'Register typed event handlers', 'Emit events with correct payload types'], starter: 'interface Events {\n  message: { text: string; from: string };\n  typing: { user: string };\n  disconnect: undefined;\n}\n\nclass Chat<E extends Record<string, any>> {\n  private handlers: Partial<{ [K in keyof E]: ((data: E[K]) => void)[] }> = {};\n  \n  on<K extends keyof E>(event: K, handler: (data: E[K]) => void): void {\n    // Register handler\n  }\n  \n  emit<K extends keyof E>(event: K, data: E[K]): void {\n    // Call all handlers\n  }\n}\n\nconst chat = new Chat<Events>();\nchat.on("message", (data) => console.log(`${data.from}: ${data.text}`));\nchat.emit("message", { text: "Hello", from: "Alice" });', solution: 'interface Events {\n  message: { text: string; from: string };\n  typing: { user: string };\n  disconnect: undefined;\n}\n\nclass Chat<E extends Record<string, any>> {\n  private handlers: Partial<{ [K in keyof E]: ((data: E[K]) => void)[] }> = {};\n  \n  on<K extends keyof E>(event: K, handler: (data: E[K]) => void): void {\n    if (!this.handlers[event]) this.handlers[event] = [];\n    this.handlers[event]!.push(handler);\n  }\n  \n  emit<K extends keyof E>(event: K, data: E[K]): void {\n    (this.handlers[event] || []).forEach(fn => fn(data));\n  }\n}\n\nconst chat = new Chat<Events>();\nchat.on("message", (data) => console.log(`${data.from}: ${data.text}`));\nchat.emit("message", { text: "Hello", from: "Alice" });', hints: ['Use Partial for optional handler arrays', 'Non-null assertion (!) after checking existence'], challenge: 'Implement a type-safe Builder pattern for constructing complex objects step by step.', reqs: ['Each method returns a more constrained type', 'Final build() only available when all required fields set', 'TypeScript errors on missing fields'], tests: [['builder.name("x").age(1).build()', 'typed object', 5]] }),
    ] }),

    T({ title: 'TypeScript with React', slug: 'ts-react-patterns', description: 'Type React components, hooks, and props for robust UI development.', language: 'typescript', difficulty: 'intermediate', duration: 45, tags: ['typescript', 'react', 'components', 'hooks'], category: 'Web Development', objectives: ['Type React component props', 'Type hooks and state', 'Use generic components'], steps: [
      S(1, { title: 'Typed React Components', content: 'TypeScript ensures React components receive the correct props and state types.', lang: 'typescript', code: 'interface ButtonProps {\n  label: string;\n  onClick: () => void;\n  variant?: "primary" | "secondary";\n  disabled?: boolean;\n}\n\nfunction Button({ label, onClick, variant = "primary", disabled = false }: ButtonProps) {\n  console.log(`Button: ${label} (${variant}) disabled=${disabled}`);\n  return { type: "button", props: { label, onClick, variant, disabled } };\n}\n\nconst btn = Button({ label: "Submit", onClick: () => console.log("clicked") });\nconsole.log(btn);', concept: 'Component props are typed with interfaces. Optional props use ?. Children are typed as ReactNode. Hooks preserve types through generics.', keyPoints: ['Interface for component props', 'Optional props with ? and defaults', 'useState<Type> for state typing', 'Event types from React namespace'], realWorld: 'Every production React app uses TypeScript for props validation, preventing prop-drilling bugs and wrong types.', mistakes: ['Using any for event handlers', 'Not typing children properly', 'Forgetting to type useRef generics'], pInstructions: ['Define typed props interface', 'Create a component with typed props', 'Add event handler types'], starter: 'interface InputProps {\n  value: string;\n  onChange: (value: string) => void;\n  label: string;\n  placeholder?: string;\n  type?: "text" | "email" | "password";\n}\n\nfunction TextInput({ value, onChange, label, placeholder = "", type = "text" }: InputProps) {\n  // Simulated component\n  console.log(`Input: ${label} = "${value}" (${type})`);\n  onChange(value + "!");\n  return { label, value, type };\n}\n\nconst input = TextInput({ value: "hello", onChange: (v) => console.log("Changed:", v), label: "Name" });\nconsole.log(input);', solution: 'interface InputProps {\n  value: string;\n  onChange: (value: string) => void;\n  label: string;\n  placeholder?: string;\n  type?: "text" | "email" | "password";\n}\n\nfunction TextInput({ value, onChange, label, placeholder = "", type = "text" }: InputProps) {\n  console.log(`Input: ${label} = "${value}" (${type})`);\n  onChange(value + "!");\n  return { label, value, type };\n}\n\nconst input = TextInput({ value: "hello", onChange: (v) => console.log("Changed:", v), label: "Name" });\nconsole.log(input);', hints: ['Destructure props with type annotation', 'Use literal union for constrained values'], challenge: 'Create a generic List<T> component that renders typed items with a render prop.', reqs: ['Generic props: items: T[], renderItem: (item: T) => ReactNode', 'Type-safe item access in renderItem', 'Support key extraction'], tests: [['List<User> with users', 'type-safe render', 5]] }),
    ] }),

    T({ title: 'TypeScript Testing Types', slug: 'ts-testing-types', description: 'Write type-level tests to ensure your types work correctly.', language: 'typescript', difficulty: 'advanced', duration: 40, tags: ['typescript', 'testing', 'type-testing', 'assertions'], objectives: ['Test type correctness', 'Use type assertions', 'Verify type constraints'], steps: [
      S(1, { title: 'Type-Level Testing', content: 'Testing types ensures your utility types and generics work correctly.', lang: 'typescript', code: '// Type equality check\ntype Equal<A, B> = A extends B ? (B extends A ? true : false) : false;\n\n// Test cases\ntype Test1 = Equal<string, string>;  // true\ntype Test2 = Equal<string, number>;  // false\n\n// Verify a utility type\ntype Nullable<T> = { [K in keyof T]: T[K] | null };\n\ninterface User { name: string; age: number; }\ntype NullableUser = Nullable<User>;\n\n// Assert expected type\ntype TestNullable = Equal<NullableUser, { name: string | null; age: number | null }>; // true\n\nconst results: [Test1, Test2, TestNullable] = [true, false, true];\nconsole.log("All type tests:", results);', concept: 'Type-level testing verifies that your generic types and utility types produce the expected output types. This catches type-level bugs at compile time.', keyPoints: ['Equal<A, B> checks type equality', 'Expect<T extends true> forces compile error', 'Test utility type outputs', 'Catch regressions in type changes'], realWorld: 'Library authors test their exported types to ensure backward compatibility and correctness.', mistakes: ['Not testing edge cases (never, any, unknown)', 'Forgetting distributive conditional types', 'Type tests that pass vacuously'], pInstructions: ['Create a type equality checker', 'Write type tests for utility types', 'Test edge cases'], starter: 'type Equal<A, B> = A extends B ? (B extends A ? true : false) : false;\n\n// Create and test a Readonly deep utility\ntype DeepReadonly<T> = {\n  readonly [K in keyof T]: T[K] extends object ? DeepReadonly<T[K]> : T[K];\n};\n\ninterface Config {\n  db: { host: string; port: number };\n  debug: boolean;\n}\n\ntype ReadonlyConfig = DeepReadonly<Config>;\n\n// Test\ntype Test = Equal<ReadonlyConfig, {\n  readonly db: DeepReadonly<{ host: string; port: number }>;\n  readonly debug: boolean;\n}>;\n\nconst test: Test = true;\nconsole.log("Type test passed:", test);', solution: 'type Equal<A, B> = A extends B ? (B extends A ? true : false) : false;\n\ntype DeepReadonly<T> = {\n  readonly [K in keyof T]: T[K] extends object ? DeepReadonly<T[K]> : T[K];\n};\n\ninterface Config {\n  db: { host: string; port: number };\n  debug: boolean;\n}\n\ntype ReadonlyConfig = DeepReadonly<Config>;\n\ntype Test = Equal<ReadonlyConfig, {\n  readonly db: DeepReadonly<{ host: string; port: number }>;\n  readonly debug: boolean;\n}>;\n\nconst test: Test = true;\nconsole.log("Type test passed:", test);', hints: ['Equal uses bidirectional extends', 'DeepReadonly recurses on object types'], challenge: 'Create a comprehensive type test suite for Partial, Required, Pick, and Omit.', reqs: ['Test with various input types', 'Test edge cases (empty objects, never)', 'All tests must compile'], tests: [['all type tests pass', 'true', 5]] }),
    ] }),

    T({ title: 'TypeScript Branded Types', slug: 'ts-branded-types', description: 'Use branded types to prevent mixing up structurally identical types.', language: 'typescript', difficulty: 'advanced', duration: 35, tags: ['typescript', 'branded-types', 'nominal', 'safety'], objectives: ['Create branded types', 'Prevent type confusion', 'Build validation constructors'], steps: [
      S(1, { title: 'Nominal Typing with Brands', content: 'Branded types add invisible tags to prevent mixing structurally identical types.', lang: 'typescript', code: 'type Brand<T, B> = T & { readonly __brand: B };\n\ntype USD = Brand<number, "USD">;\ntype EUR = Brand<number, "EUR">;\ntype UserId = Brand<string, "UserId">;\ntype Email = Brand<string, "Email">;\n\nfunction usd(amount: number): USD { return amount as USD; }\nfunction eur(amount: number): EUR { return amount as EUR; }\n\nfunction processPayment(amount: USD): void {\n  console.log(`Processing $${amount}`);\n}\n\nprocessPayment(usd(100));  // OK\n// processPayment(eur(100)); // Error! EUR is not USD\n// processPayment(100);       // Error! plain number\n\nconsole.log("Payment processed");', concept: 'TypeScript uses structural typing, so two types with the same shape are interchangeable. Branded types add a phantom property to differentiate structurally identical types.', keyPoints: ['Brand adds invisible __brand tag', 'Prevents accidental type mixing', 'Constructor functions validate + brand', 'Phantom types for safety'], realWorld: 'Financial systems must never mix currencies. User IDs and post IDs are both strings but shouldn\'t be interchangeable.', mistakes: ['Accessing __brand at runtime', 'Forgetting to use constructor functions', 'Over-branding simple types'], pInstructions: ['Create branded types for IDs', 'Add validation in constructors', 'Try to mix branded types (see errors)'], starter: 'type Brand<T, B> = T & { readonly __brand: B };\n\ntype UserId = Brand<string, "UserId">;\ntype PostId = Brand<string, "PostId">;\n\nfunction userId(id: string): UserId {\n  if (!id.startsWith("user_")) throw new Error("Invalid user ID");\n  return id as UserId;\n}\n\nfunction postId(id: string): PostId {\n  if (!id.startsWith("post_")) throw new Error("Invalid post ID");\n  return id as PostId;\n}\n\nfunction getUser(id: UserId): string { return `User: ${id}`; }\n\nconst uid = userId("user_123");\nconsole.log(getUser(uid));', solution: 'type Brand<T, B> = T & { readonly __brand: B };\n\ntype UserId = Brand<string, "UserId">;\ntype PostId = Brand<string, "PostId">;\n\nfunction userId(id: string): UserId {\n  if (!id.startsWith("user_")) throw new Error("Invalid user ID");\n  return id as UserId;\n}\n\nfunction postId(id: string): PostId {\n  if (!id.startsWith("post_")) throw new Error("Invalid post ID");\n  return id as PostId;\n}\n\nfunction getUser(id: UserId): string { return `User: ${id}`; }\n\nconst uid = userId("user_123");\nconsole.log(getUser(uid));', hints: ['Brand intersects T with a phantom property', 'Validation happens in constructor function'], challenge: 'Build a validated email type that only accepts properly formatted emails.', reqs: ['ValidatedEmail branded type', 'Constructor validates format', 'Functions accept only ValidatedEmail, not plain string'], tests: [['email("a@b.com")', 'ValidatedEmail type', 5], ['email("invalid")', 'throws', 5]] }),
    ] }),

    T({ title: 'TypeScript Record and Index Types', slug: 'ts-record-index', description: 'Use Record, index signatures, and dynamic key types for flexible objects.', language: 'typescript', difficulty: 'intermediate', duration: 35, tags: ['typescript', 'record', 'index-signatures', 'dynamic'], objectives: ['Use Record for typed maps', 'Write index signatures', 'Type dynamic property access'], steps: [
      S(1, { title: 'Record and Index Signatures', content: 'Record creates typed maps. Index signatures allow dynamic keys.', lang: 'typescript', code: 'type Scores = Record<string, number>;\nconst scores: Scores = { Alice: 92, Bob: 78, Charlie: 95 };\n\n// Index signature\ninterface Cache {\n  [key: string]: { value: any; expires: number };\n}\n\nconst cache: Cache = {};\ncache["user:1"] = { value: { name: "Alice" }, expires: Date.now() + 3600 };\n\n// Typed keys with Record\ntype Fruit = "apple" | "banana" | "cherry";\ntype FruitPrices = Record<Fruit, number>;\nconst prices: FruitPrices = { apple: 1.5, banana: 0.75, cherry: 3.0 };\nconsole.log(prices.apple);', concept: 'Record<Keys, Value> creates an object type with specified key and value types. Index signatures [key: string]: T allow any string key with typed values.', keyPoints: ['Record<K, V> for known key sets', 'Index signature for dynamic keys', 'Record enforces all keys present', 'Mapped types for transformations'], realWorld: 'Config files with typed sections, translation dictionaries, feature flags with boolean values.', mistakes: ['Record forces all keys — use Partial<Record> for optional', 'Index signature conflicts with specific properties', 'Not using Map when keys are dynamic'], pInstructions: ['Create a Record with enum keys', 'Use index signatures for dynamic data', 'Combine both patterns'], starter: 'type Permission = "read" | "write" | "delete";\ntype Role = "admin" | "editor" | "viewer";\n\n// Define permissions for each role\ntype RolePermissions = Record<Role, Permission[]>;\n\nconst permissions: RolePermissions = {\n  admin: ["read", "write", "delete"],\n  editor: ["read", "write"],\n  viewer: ["read"]\n};\n\nfunction hasPermission(role: Role, perm: Permission): boolean {\n  return permissions[role].includes(perm);\n}\n\nconsole.log(hasPermission("editor", "write"));   // true\nconsole.log(hasPermission("viewer", "delete"));  // false', solution: 'type Permission = "read" | "write" | "delete";\ntype Role = "admin" | "editor" | "viewer";\n\ntype RolePermissions = Record<Role, Permission[]>;\n\nconst permissions: RolePermissions = {\n  admin: ["read", "write", "delete"],\n  editor: ["read", "write"],\n  viewer: ["read"]\n};\n\nfunction hasPermission(role: Role, perm: Permission): boolean {\n  return permissions[role].includes(perm);\n}\n\nconsole.log(hasPermission("editor", "write"));\nconsole.log(hasPermission("viewer", "delete"));', hints: ['Record ensures all roles have permissions', 'Array includes() checks membership'], challenge: 'Build a type-safe i18n system using Record for translations.', reqs: ['Translation keys as type', 'Multiple locale support', 'Missing translation detection'], tests: [['t("greeting", "en")', '"Hello"', 5]] }),
    ] }),

    T({ title: 'TypeScript Tuple Types', slug: 'ts-tuple-types', description: 'Use typed tuples for fixed-length arrays with known element types.', language: 'typescript', difficulty: 'intermediate', duration: 30, tags: ['typescript', 'tuples', 'arrays', 'types'], objectives: ['Define tuple types', 'Use labeled tuples', 'Apply variadic tuple types'], steps: [
      S(1, { title: 'Tuple Basics', content: 'Tuples are fixed-length arrays where each position has a specific type.', lang: 'typescript', code: '// Basic tuple\ntype Point = [number, number];\nconst origin: Point = [0, 0];\n\n// Labeled tuple\ntype Range = [start: number, end: number];\nconst range: Range = [1, 10];\n\n// Mixed types\ntype UserTuple = [id: number, name: string, active: boolean];\nconst user: UserTuple = [1, "Alice", true];\n\n// Destructuring\nconst [id, name, active] = user;\nconsole.log(id, name, active);', concept: 'Tuples differ from arrays — they have fixed length and typed positions. Rest elements allow variable-length tails. Labeled tuples improve readability.', keyPoints: ['Fixed length and position types', 'Labels for documentation', 'Rest elements: [string, ...number[]]', 'Destructuring preserves types'], realWorld: 'React hooks return tuples: [value, setValue]. Database rows as typed tuples.', mistakes: ['Confusing tuple with array type', 'Accessing out-of-bounds indices', 'Using tuples when objects are clearer'], pInstructions: ['Create typed tuples', 'Destructure tuples', 'Use tuples as function return types'], starter: '// Function returning a tuple\nfunction divide(a: number, b: number): [result: number, remainder: number] {\n  return [Math.floor(a / b), a % b];\n}\n\nconst [quotient, remainder] = divide(17, 5);\nconsole.log(`17 / 5 = ${quotient} remainder ${remainder}`);\n\n// Tuple for coordinates with optional z\ntype Coord = [x: number, y: number, z?: number];\nconst point2d: Coord = [1, 2];\nconst point3d: Coord = [1, 2, 3];\nconsole.log(point2d, point3d);', solution: 'function divide(a: number, b: number): [result: number, remainder: number] {\n  return [Math.floor(a / b), a % b];\n}\n\nconst [quotient, remainder] = divide(17, 5);\nconsole.log(`17 / 5 = ${quotient} remainder ${remainder}`);\n\ntype Coord = [x: number, y: number, z?: number];\nconst point2d: Coord = [1, 2];\nconst point3d: Coord = [1, 2, 3];\nconsole.log(point2d, point3d);', hints: ['Return type annotation: [type1, type2]', 'Optional elements use ?'], challenge: 'Build a type-safe SQL query builder using tuples for column selection.', reqs: ['Tuple for selected columns', 'Return type matches selected columns', 'Type-safe WHERE clauses'], tests: [['select("name","age")', 'typed result', 5]] }),
    ] }),

    T({ title: 'TypeScript Intersection Types', slug: 'ts-intersection-types', description: 'Combine multiple types into one with intersection types.', language: 'typescript', difficulty: 'intermediate', duration: 30, tags: ['typescript', 'intersection', 'types', 'composition'], objectives: ['Combine types with &', 'Use intersections for mixins', 'Understand intersection semantics'], steps: [
      S(1, { title: 'Intersection Type Composition', content: 'Intersection types combine multiple types into one that has all their properties.', lang: 'typescript', code: 'interface HasId { id: number; }\ninterface HasName { name: string; }\ninterface HasEmail { email: string; }\n\ntype User = HasId & HasName & HasEmail;\n\nconst user: User = { id: 1, name: "Alice", email: "alice@test.com" };\nconsole.log(user);\n\n// Mixins with intersection\ntype Timestamped<T> = T & { createdAt: Date; updatedAt: Date };\ntype SoftDeletable<T> = T & { deletedAt: Date | null };\n\ntype FullUser = Timestamped<SoftDeletable<User>>;\nconst fullUser: FullUser = {\n  id: 1, name: "Alice", email: "alice@test.com",\n  createdAt: new Date(), updatedAt: new Date(), deletedAt: null\n};\nconsole.log(fullUser.name);', concept: 'Intersection types (A & B) create a type that must satisfy both A and B. This enables composition — building complex types from simpler pieces.', keyPoints: ['& means "and" — must have all properties', 'Great for mixins and composition', 'Conflicting properties become never', 'Prefer composition over deep inheritance'], realWorld: 'API models: BaseEntity & WithTimestamps & WithSoftDelete. Middleware adds properties to request objects.', mistakes: ['Conflicting property types result in never', 'Deep intersection can be confusing', 'Not using type aliases for readability'], pInstructions: ['Combine interfaces with intersection', 'Create generic type mixins', 'Build a complex type from pieces'], starter: 'interface Printable {\n  toString(): string;\n}\n\ninterface Serializable {\n  toJSON(): object;\n}\n\ninterface Validatable {\n  validate(): boolean;\n}\n\ntype Model = Printable & Serializable & Validatable;\n\nclass UserModel implements Model {\n  constructor(public name: string, public age: number) {}\n  toString() { return `${this.name} (${this.age})`; }\n  toJSON() { return { name: this.name, age: this.age }; }\n  validate() { return this.name.length > 0 && this.age > 0; }\n}\n\nconst user = new UserModel("Alice", 30);\nconsole.log(user.toString());\nconsole.log(user.toJSON());\nconsole.log(user.validate());', solution: 'interface Printable {\n  toString(): string;\n}\n\ninterface Serializable {\n  toJSON(): object;\n}\n\ninterface Validatable {\n  validate(): boolean;\n}\n\ntype Model = Printable & Serializable & Validatable;\n\nclass UserModel implements Model {\n  constructor(public name: string, public age: number) {}\n  toString() { return `${this.name} (${this.age})`; }\n  toJSON() { return { name: this.name, age: this.age }; }\n  validate() { return this.name.length > 0 && this.age > 0; }\n}\n\nconst user = new UserModel("Alice", 30);\nconsole.log(user.toString());\nconsole.log(user.toJSON());\nconsole.log(user.validate());', hints: ['implements enforces all interface methods', 'Intersection = must satisfy all parts'], challenge: 'Create a type-safe middleware system where each middleware adds typed properties to context.', reqs: ['Each middleware adds specific type properties', 'Chain middlewares with intersection', 'Final handler sees all added properties'], tests: [['auth middleware adds user', 'context.user typed', 5]] }),
    ] }),

  ];
};
